class Solution:
    def shortestAlternatingPaths(self, n, redEdges, blueEdges):
        INF = float('inf')
        radj = [[] for _ in range(n)]
        badj = [[] for _ in range(n)]
        for a, b in redEdges:
            radj[a].append(b)
        for a, b in blueEdges:
            badj[a].append(b)
        # dist[node][color]: color 0 = arrived via red, 1 = via blue
        dist = [[INF, INF] for _ in range(n)]
        # Bellman-Ford-style relaxation over states
        dist[0][0] = 0
        dist[0][1] = 0
        changed = True
        while changed:
            changed = False
            for node in range(n):
                for color in (0, 1):
                    d = dist[node][color]
                    if d == INF:
                        continue
                    # last edge color was 'color'; next must be opposite
                    if color == 0:
                        nbrs, ncol = badj[node], 1
                    else:
                        nbrs, ncol = radj[node], 0
                    for nxt in nbrs:
                        if d + 1 < dist[nxt][ncol]:
                            dist[nxt][ncol] = d + 1
                            changed = True
        ans = []
        for node in range(n):
            best = min(dist[node][0], dist[node][1])
            ans.append(-1 if best == INF else best)
        return ans

