class Solution:
    def shortestAlternatingPaths(self, n, redEdges, blueEdges):
        from collections import deque
        radj = [[] for _ in range(n)]
        badj = [[] for _ in range(n)]
        for a, b in redEdges:
            radj[a].append(b)
        for a, b in blueEdges:
            badj[a].append(b)
        INF = float('inf')
        dist = [[INF, INF] for _ in range(n)]
        dist[0][0] = 0
        dist[0][1] = 0
        q = deque([(0, 0), (0, 1)])
        while q:
            node, color = q.popleft()
            d = dist[node][color]
            if color == 0:
                nbrs, ncol = badj[node], 1
            else:
                nbrs, ncol = radj[node], 0
            for nxt in nbrs:
                if dist[nxt][ncol] == INF:
                    dist[nxt][ncol] = d + 1
                    q.append((nxt, ncol))
        ans = []
        for node in range(n):
            best = min(dist[node][0], dist[node][1])
            ans.append(-1 if best == INF else best)
        return ans

