var shortestAlternatingPaths = function(n, redEdges, blueEdges) {
    const radj = Array.from({length: n}, () => []);
    const badj = Array.from({length: n}, () => []);
    for (const [a, b] of redEdges) radj[a].push(b);
    for (const [a, b] of blueEdges) badj[a].push(b);
    const INF = Infinity;
    const dist = Array.from({length: n}, () => [INF, INF]);
    dist[0][0] = 0;
    dist[0][1] = 0;
    const q = [[0, 0], [0, 1]];
    let head = 0;
    while (head < q.length) {
        const [node, color] = q[head++];
        const d = dist[node][color];
        const nbrs = color === 0 ? badj[node] : radj[node];
        const ncol = color === 0 ? 1 : 0;
        for (const nxt of nbrs) {
            if (dist[nxt][ncol] === INF) {
                dist[nxt][ncol] = d + 1;
                q.push([nxt, ncol]);
            }
        }
    }
    const ans = [];
    for (let node = 0; node < n; node++) {
        const best = Math.min(dist[node][0], dist[node][1]);
        ans.push(best === INF ? -1 : best);
    }
    return ans;
};
